import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"在 Linux 上安裝 Java","description":"在 Linux 上安裝 Java 的逐步指南。","frontmatter":{"title":"在 Linux 上安裝 Java","description":"在 Linux 上安裝 Java 的逐步指南。","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"zh_tw/1.20.4/players/installing-java/linux.md","filePath":"versions/1.20.4/translated/zh_tw/players/installing-java/linux.md","lastUpdated":1739538073000}`);var o={name:`zh_tw/1.20.4/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 Linux 上安裝 Java <a class="header-anchor" href="#h1" aria-label="Permalink to “在 Linux 上安裝 Java”">​</a></h1><p>這個指南將引導你在 Linux 上安裝 Java 17。</p><h2 id="_1-驗證-java-是否安裝" tabindex="-1">1. 驗證 Java 是否安裝 <a class="header-anchor" href="#_1-驗證-java-是否安裝" aria-label="Permalink to “1. 驗證 Java 是否安裝”">​</a></h2><p>開啟終端機，輸入 <code>java -version</code>，然後按下 <kbd>Enter</kbd> 鍵。</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="終端機中輸入了「java -version」" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>要使用大多數現代的 Minecraft，你需要至少安裝 Java 17。 如果這個命令顯示低於 17 的任何版本，你需要更新現有的 Java 安裝。 如果你打算開發模組，你應參考另一個指南。 如果你打算開發模組，你應參考另一個指南。 如果你打算開發模組，你應參考另一個指南。</p></div><h2 id="_2-下載並安裝-java-17" tabindex="-1">2. 下載並安裝 Java 17 <a class="header-anchor" href="#_2-下載並安裝-java-17" aria-label="Permalink to “2. 下載並安裝 Java 17”">​</a></h2><p>我們建議使用 OpenJDK 17，在大多數 Linux 發行版中都可用。</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>有關在 Arch Linux 上安裝 Java 的更多資訊，請參閱 <a href="https://wiki.archlinuxcn.org/wiki/Java" target="_blank" rel="noreferrer">Arch Linux Wiki</a>。</p></div><p>你可以從官方儲存庫安裝最新的 JRE：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你在沒有圖形化介面的伺服器上執行，則可以安裝無頭版本：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你打算開發模組，則需要 JDK：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian／Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian／Ubuntu”">​</a></h3><p>你可以使用 apt 安裝 Java 17，使用以下命令：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-17-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>你可以使用 dnf 安裝 Java 17，使用以下命令：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你不需要圖形化介面，則可以安裝無頭版本：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你打算開發模組，則需要 JDK：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="其他-linux-發行版" tabindex="-1">其他 Linux 發行版 <a class="header-anchor" href="#其他-linux-發行版" aria-label="Permalink to “其他 Linux 發行版”">​</a></h3><p>如果你的發行版未在上述清單中，你可以從 <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Eclipse Temurin</a> 下載最新的 JRE。</p><p>如果你打算開發模組，你應參考另一個指南。</p><h2 id="_3-驗證-java-17-是否安裝" tabindex="-1">3. 驗證 Java 17 是否安裝 <a class="header-anchor" href="#_3-驗證-java-17-是否安裝" aria-label="Permalink to “3. 驗證 Java 17 是否安裝”">​</a></h2><p>安裝完成後，你可以開啟終端機，輸入 <code>java -version</code> 來驗證是否安裝了 Java 17。</p><p>如果這個命令成功執行，你將看到類似於以前顯示的內容，其中顯示了 Java 版本：</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="終端機中輸入了「java -version」" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};